mapper.insert:
/** UsptEvlStepDao.insert */
insert into uspt_evl_step (
	   evl_step_id
	 , evl_plan_id
	 , evl_step_nm
	 , sort_ordr_no
	 , evl_step_sttus_cd
	 , slctn_target_co
	 , drpt_stdr_cd
	 , top_lwet_excl
	 , dspth
	 , dspth_dt
	 , creator_id
	 , created_dt
	 , updater_id
	 , updated_dt
) values (
	   #{evlStepId}
	 , #{evlPlanId}
	 , #{evlStepNm}
	 , #{sortOrdrNo}
	 , #{evlStepSttusCd}
	 , #{slctnTargetCo}
	 , #{drptStdrCd}
	 , #{topLwetExcl}
	 , #{dspth}
	 , #{dspthDt}
	 , #{creatorId}
	 , #{createdDt}
	 , #{updaterId}
	 , #{updatedDt}
)

mapper.update:
/** UsptEvlStepDao.update */
update uspt_evl_step set
	   evl_step_id               = #{evlStepId}
	 , evl_plan_id               = #{evlPlanId}
	 , evl_step_nm               = #{evlStepNm}
	 , sort_ordr_no              = #{sortOrdrNo}
	 , evl_step_sttus_cd         = #{evlStepSttusCd}
	 , slctn_target_co           = #{slctnTargetCo}
	 , drpt_stdr_cd              = #{drptStdrCd}
	 , top_lwet_excl             = #{topLwetExcl}
	 , dspth                     = #{dspth}
	 , dspth_dt                  = #{dspthDt}
	 , creator_id                = #{creatorId}
	 , created_dt                = #{createdDt}
	 , updater_id                = #{updaterId}
	 , updated_dt                = #{updatedDt}
 where evl_step_id = #{evlStepId}

mapper.delete:
/** UsptEvlStepDao.delete */
delete
  from uspt_evl_step
 where evl_step_id = #{evlStepId}

/** UsptEvlStepDao.deleteBySectId */
delete
  from uspt_evl_step
 where evl_step_id in (
 					   select evl_step_id
 					     from uspt_evl_cmit
						where sect_id = #{sectId}
					  )
